css.value:
.NOPEpage-content {
  --page-primary-light-color: rgb(243, 242, 239);
}

.NOPEpage-sidebar-background {
  background-color: var(--page-primary-light-color);
}

.NOPEpage-header .basics-items {
  border: none;
  padding: 0;
  order: 3
}
.NOPEpage-header .page-picture {
  order: 2
}

.NOPEpage-header .text-center {
  text-align: left ;
}

.NOPEpage-header .basics-name {
  font-size: 2.8em;
  line-height: 1;
  color: #17535B;
}

.NOPEpage-header .basics-headline {
  font-size: 1.7em;
  color: #17535B;
  font-style: italic;
}

.NOPEpage-section > h6 {
  background-color: var(--page-primary-color);
  border: none;
  color: var(--page-secondary-color);
  text-align: center;
  margin-bottom: 0.8em;
}

.NOPEsection-item-header {
  padding-bottom: 0.2em;
}

.experience-item-roles {
  border-left: 1px solid var(--page-primary-color);
  padding-left: 10pt;
  margin-left: 2pt;
}

.experience-item-roles li {
  margin-inline-start: 1.5rem;
}

.basics-items .ph-linkedin-logo {
  position: relative;
  top: 1px;
}

.basics-items .basics-item-email svg {
  position: relative;
  top: 1px;        
}

.basics-items .ph-github-logo {
  position: relative;
  top: 1px;
}
.basics-items  .basics-item-location svg {
  position: relative;
  bottom: 1px;
}
.basics-items .basics-item-location {
  order: 100;
  padding: 0;
  border: none;
  margin-left: auto;
}

.basics-items {
    column-gap: 5pt;
}

.experience-item-role > div:first-child {
  grid-template-columns: repeat(1, minmax(0, 1fr));
}

.experience-item-role-position {
  font-weight: 600;
}

.page-1 .section-item-experience:nth-child(2) .experience-item-header div, .page-1 .section-item-experience:nth-child(2) .experience-item-header span {
  display: block;
  text-align: left;
}

.page-1 .section-item-experience:nth-child(3) .experience-item-header div, .page-1 .section-item-experience:nth-child(3) .experience-item-header span {
  display: block;
  text-align: left;
}

.experience-item-role .items-start {
  display: flex; 
}
.page-section-experience .section-content {
  row-gap: 2pt
}

.page-section-skills .section-content {
  row-gap: 4pt;
}

.experience-item-website {
  padding-bottom: 4pt;
}
